180	//
181	// copy -- CopyAtom
182	//
183	
184	template <class... CopyArgs,
185	          class SrcEngine, class SrcLayout,
186	          class DstEngine, class DstLayout>
187	CUTE_HOST_DEVICE
188	void
189	copy(Copy_Atom<CopyArgs...>       const& copy_atom,
190	     Tensor<SrcEngine, SrcLayout> const& src,       // (V,Rest...)
191	     Tensor<DstEngine, DstLayout>      & dst)       // (V,Rest...)
192	{
193	  static_assert(SrcLayout::rank == DstLayout::rank, "CopyAtom rank-mismatch.");
194	
195	  if constexpr (SrcLayout::rank == 1) {   // Dispatch the copy
196	    copy_atom.call(src, dst);
197	  } else {                                // Loop over all but the first mode
198	    constexpr int R = SrcLayout::rank;
199	    Tensor src_v = group_modes<1,R>(src);
200	    Tensor dst_v = group_modes<1,R>(dst);
201	
202	    if constexpr (is_static<decltype(shape(src_v))>::value && is_static<decltype(shape(dst_v))>::value) {
203	      CUTE_STATIC_ASSERT_V(size<1>(src_v) == size<1>(dst_v));
204	
205	      // AutoFilter on the Rest-mode
206	      auto dst_null = nullspace(layout<1>(dst_v));
207	
208	      Tensor dst_n = zipped_divide(dst_v, make_tile(shape<0>(dst_v), dst_null));  // ((V, NLL), (_1, Rest))
209	      Tensor src_n = zipped_divide(src_v, make_tile(shape<0>(src_v), dst_null));  // ((V, NLL), (_1, Rest))
210	
211	      CUTE_STATIC_ASSERT_V(size<1>(src_n) == size<1>(dst_n));
212	      CUTE_STATIC_ASSERT_V((cosize<0,1>(dst_n.layout()) == Int<1>{}), "Nullspace definition error");
213	      CUTE_STATIC_ASSERT_V((cosize<0,1>(src_n.layout()) == Int<1>{}), "Error: Ambiguous scatter detected in copy");
214	      CUTE_STATIC_ASSERT_V((size<1,0>(dst_n) == Int<1>{}));
215	      CUTE_STATIC_ASSERT_V((size<1,0>(src_n) == Int<1>{}));
216	
217	      Tensor dst_c = dst_n(make_coord(_,Int<0>{}),make_coord(Int<0>{},_));        // (V, Rest)
218	      Tensor src_c = src_n(make_coord(_,Int<0>{}),make_coord(Int<0>{},_));        // (V, Rest)
219	
220	      CUTE_STATIC_ASSERT_V( size<1>(src_c) ==  size<1>(dst_c));
221	      CUTE_STATIC_ASSERT_V(shape<0>(dst_c) == shape<0>(dst));
222	      CUTE_STATIC_ASSERT_V(shape<0>(src_c) == shape<0>(src));
223	
224	      CUTE_UNROLL
225	      for (int i = 0; i < size<1>(dst_c); ++i) {
226	        copy_atom.call(src_c(_,i), dst_c(_,i));
227	      }
228	    } else {
229	      CUTE_UNROLL
230	      for (int i = 0; i < size<1>(dst_v); ++i) {
231	        copy_atom.call(src_v(_,i), dst_v(_,i));
232	      }
233	    }
234	  }
235	}
