241	// Specialization for AutoVectorizingCopyAssumedAlignment<MaxVecBits>
242	template <int MaxVecBits,
243	          class SrcEngine, class SrcLayout,
244	          class DstEngine, class DstLayout>
245	CUTE_HOST_DEVICE
246	void
247	copy(AutoVectorizingCopyWithAssumedAlignment<MaxVecBits> const&,
248	     Tensor<SrcEngine, SrcLayout>                        const& src,
249	     Tensor<DstEngine, DstLayout>                             & dst)
250	{
251	  constexpr int common_elem = CUTE_STATIC_V(max_common_vector(src, dst));
252	  static_assert(is_integral<decltype(Int<common_elem>{} * sizeof_bits_v<typename DstEngine::value_type>)>::value, "Error: Attempting a subbit write!");
253	
254	  if constexpr (common_elem > 1)
255	  {
256	    constexpr int align_bits = CUTE_STATIC_V(gcd(max_alignment(src), max_alignment(dst), Int<MaxVecBits>{}));
257	    constexpr int vec_bits   = gcd(common_elem * sizeof_bits_v<typename DstEngine::value_type>, align_bits);
258	
259	    if constexpr ((vec_bits % 8) == 0 && sizeof_bits_v<typename DstEngine::value_type> < Int<vec_bits>{})
260	    {
261	      // If more than one element vectorizes to a multiple of 8bits that is larger than the value_type, then recast and copy
262	      using VecType = uint_bit_t<vec_bits>;
263	
264	      // Recast
265	      Tensor src_v = recast<VecType>(src);
266	      Tensor dst_v = recast<VecType>(dst);
267	      return copy_if(constant_fn<true_type>{}, src_v, dst_v);
268	    } else {
269	      return copy_if(constant_fn<true_type>{}, src, dst);
270	    }
271	  } else {
272	    return copy_if(constant_fn<true_type>{}, src, dst);
273	  }
274	}
